mapper.select:
/* com.educare.edu.comn.mapper.QrCodeMapper.selectByFeedback */
select *
  from t_qr_code
 where qr_type = #{qrType}
   and edu_seq = #{eduSeq}

/* com.educare.edu.comn.mapper.QrCodeMapper.selectByEdu */
select *
  from t_qr_code
 where edu_seq = #{eduSeq}
   and qr_type in ('1', '2', '3')

mapper.update:
/* com.educare.edu.comn.mapper.QrCodeMapper.updateByPk */
	update t_qr_code
	set qr_key=#{qrKey}
		,gen_de = #{genDe}
		 ,qr_dt = #{qrDt} 
		 ,qr_begin_de = #{qrBeginDe} 
		 ,qr_end_de = #{qrEndDe} 
	where qr_seq=#{qrSeq}
